    source_row integer,
    tool_code text,
    tool_name text,
    tool_spec text,
    material text,
    unit_price numeric,
    usage text,
    remarks text
  )
), upserted as (
  insert into public.tooling_data (
    tool_code,
    tool_name,
    tool_spec,
    material,
    unit_price,
    usage,
    remarks
  )
  select
    tool_code,
    tool_name,
    tool_spec,
    material,
    unit_price,
    usage,
    remarks
  from import_rows
  on conflict (tool_code) do update
  set tool_name = excluded.tool_name,
    tool_spec = excluded.tool_spec,
    material = excluded.material,
    unit_price = excluded.unit_price,
    usage = excluded.usage,
    remarks = excluded.remarks,
    updated_at = now()
  returning tool_code
)
select count(*) as affected_rows from upserted;
